@Query(
            value = "SELECT COUNT(*) FROM hotel_searches " +
                    "WHERE hotel_id = :hotelId " +
                    "AND check_in  = :checkIn " +
                    "AND check_out = :checkOut " +
                    "AND ages      = :agesJson",
            nativeQuery = true
    )
    long countBySearchParameters(
            @Param("hotelId")   String hotelId,
            @Param("checkIn")   java.time.LocalDate checkIn,
            @Param("checkOut")  java.time.LocalDate checkOut,
            @Param("agesJson")  String agesJson
    );

